var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"불러 주셔서 감사합니다, 그레이스 님. 오늘도 이 한 몸 불태워 안전하게 모십지요!","JPN":"お声をかけてくださってありがとうございます、グレース様。今日もこの私めが、体を張って安全にご案内いたしましょう！","ENG":"Thank you for calling me again, Dame Grace! I'll give it my all to get you there safely!","TWN":"感謝你的召喚，葛瑞絲小姐。今天我也會燃燒自己，確保你的安全！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이쪽이야말로 잘 부탁드립니다, 클링턴 씨.","JPN":"こちらこそよろしくお願いいたします、クリントンさん。","ENG":"The pleasure is mine, Mr. Clinton.","TWN":"這邊才是要請多關照了，克林頓先生。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후. 영애 분도 잘 부탁드려요.","JPN":"ふふ。ご令嬢もよろしくお願いいたします。","ENG":"Haha. Milady, I'm counting on you.","TWN":"呵呵，也請馬千金多關照囉。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"결혼했습니다!","JPN":"つがいができました！","ENG":"She's married now!","TWN":"牠結婚了！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어머. 어쩐지 성숙해졌다 싶더니.","JPN":"まあ。どうりで大人っぽくなったと思いました。","ENG":"Oh? No wonder she seems more mature.","TWN":"哎呀。難怪覺得變成熟了呢。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……또, 이 마부의 마차를 타는 겁니까?","JPN":"……また、この御者の馬車に乗るのですか？","ENG":"...Are we seriously riding with this coachman again?","TWN":"……又要坐這馬車夫的馬車嗎？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"클링턴 씨는 제국 내에서도 손꼽히는 마부이십니다.","JPN":"クリントンさんは帝国でも有名な御者なのです。","ENG":"Mr. Clinton is one of the finest coachmen in the Empire.","TWN":"克林頓先生是帝國內數一數二的馬夫。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"위험도가 높은 원정에 이보다 제격인 분이 어디 있겠습니까?","JPN":"危険度の高い遠征に、彼より相応しい方はいません。","ENG":"For an expedition this dangerous, you won't find a better choice.","TWN":"還有誰比你更適合高風險的遠征呢？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That's...","TWN":"那個……"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"흔들림이 걱정되신다면 손잡이를 배치해드릴까요?","JPN":"揺れが心配でしたら、手すりを設置しましょうか？","ENG":"If you're worried about the bumps, I can have a handrail installed.","TWN":"如果你擔心晃動的話，要不要給你裝一個扶手？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"괜찮습니다.","JPN":"結構です。","ENG":"No need.","TWN":"沒關係。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후. 문제가 없다면 이만 출발하지요.","JPN":"ふふ。問題がなければ出発しましょう。","ENG":"Haha. If there's nothing else, then let's be off.","TWN":"呵呵。如果沒有問題的話，那我們就出發吧。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"부인. 잠시 괜찮으십니까?","JPN":"夫人。よろしいですか？","ENG":"Ma'am. Do you have a moment?","TWN":"夫人，打擾一下？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"여쭤볼 게 있습니다만…….","JPN":"聞きたいことがあるのですが……","ENG":"There's something I'd like to ask...","TWN":"我有件事想問……"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어머. 지난번에 못한 <color=#ffd34c>질문</color>을 하실 생각이 드셨습니까?","JPN":"あら。先日果たせなかった<color=#ffd34c>質問</color>のことでしょうか？","ENG":"Oh my. Have you finally decided to ask the <color=#ffd34c>question</color> you couldn't last time?","TWN":"那是<color=#ffd34c>問題</color>嗎?"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"농담입니다. 대답하기 곤란한 것을 제외하곤 답변해드릴 터이니, 편히 말씀해 보시지요.","JPN":"冗談です。答えづらいことでなければお答えしますので、お気楽にどうぞ。","ENG":"I'm joking. Unless it's something I truly can't answer, I'll do my best. Go ahead.","TWN":"開玩笑的。除了無法回答的問題，我會儘量回答的，請隨意提問吧。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"별건 아니고, 병력의 이동 대형이 조금 의아했을 뿐입니다.","JPN":"大したことではないのですが、兵力の移動隊形が少しおかしいと思ったのです。","ENG":"It's nothing major, I was just curious about the formation.","TWN":"沒什麼，只是部隊的移動陣型有些奇怪而已。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"현재의 방진은 장기 기동에 적합한 전술로는 보이지 않는군요.","JPN":"現在の方陣は長期の機動に適合しているようには思えません。","ENG":"It doesn't look suited for long-range movement.","TWN":"目前的陣型似乎不適合長時間機動的戰術。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"타당한 지적입니다. 전술적으로 봤을 때 팔랑크스는 수세적인 진법에 가깝지요.","JPN":"正しい指摘です。戦術的な観点からすれば、ファランクスは守りを重視した陣形に近いです。","ENG":"A valid point. Tactically, a phalanx is a defensive formation.","TWN":"這是一個合理的疑問。從戰術上看，方陣更接近於防禦陣型。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"허나 병사들의 본분이 제 호위임을 생각하면, 현 상황에서는 유효한 진법입니다.","JPN":"ですが、兵士たちの本分が私の護衛であることを考えると、今の状況では有効な陣形なのです。","ENG":"But considering the soldiers are here to guard me, it's the best fit for our current situation.","TWN":"不過考慮到士兵們的職責是護衛我，在當前情況下，這是一種有效的陣法。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"지킨다? 이 병사들이 전부 말입니까?","JPN":"守る？　この数の兵士全員がですか？","ENG":"Guard you? All of them?","TWN":"保護嗎？這些士兵全都是嗎？"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"대체 무엇으로부터-.","JPN":"いったい何から……","ENG":"Guard you from wh–","TWN":"究竟從何而來-"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"모두 정지! 전방에 대량의 괴수가 나타났다!","JPN":"全員、止まれ！　前方に大量の怪獣が現れた！","ENG":"All units, halt! Large group of C.O.s spotted ahead!","TWN":"全部停下！前方出現大量怪物！"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"무기를 갖추고 전투에 대비하라! 놈들이 접근하기 전에 선수를 친다!!","JPN":"武器を構え、戦闘に備えよ！　やつらが近づく前に先手を打つ！","ENG":"Ready your weapons! Engage before they reach us!","TWN":"準備武器，迎戰！在他們接近之前先發制人！！"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};